SELECT 
  (SELECT COUNT(*) FROM batch_expenses WHERE batch_id = 1) AS total_expenses,
  (SELECT COUNT(*) FROM batch_incomes WHERE batch_id = 1) AS total_incomes;

SELECT SUM(amount) AS total_expenses
FROM batch_expenses
WHERE batch_id = 1;

SELECT batch_name, salary
FROM batches
ORDER BY batch_name ASC;

SELECT *
FROM batches
ORDER BY start_date ASC;

SELECT 
  (SELECT COUNT(DISTINCT batch_id) FROM batch_expenses) AS total_expenses_batches,
  (SELECT COUNT(DISTINCT batch_id) FROM batch_incomes) AS total_incomes_batches;

SELECT 
    (SELECT COUNT(*) FROM batch_incomes bi WHERE bi.batch_id = (SELECT batch_id FROM batches WHERE batch_name = 'batch_2')) AS incomes,
    (SELECT COUNT(*) FROM batch_expenses be WHERE be.batch_id = (SELECT batch_id FROM batches WHERE batch_name = 'batch_2')) AS expenses;

SELECT COUNT(expense_id)
FROM batch_expenses
WHERE batch_id = 1;

SELECT * 
FROM batch_financial_reports
WHERE batch_id = 1;

SELECT COUNT(*) AS total_documents
FROM financial_documents
WHERE file_type = 'PDF';
